System.register([],function(w,n){var e,a,o,i;return{setters:[],execute:function(){a=(w,n,e,a,o,i)=>({id:w,type:"dialogue",speaker:n,speakerKey:e,text:a,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:i}),o=(w,n,e,a,o)=>({id:w,type:"quiz",text:n,quiz:e,onCorrect:a,onWrong:o,speaker:""}),i=(w,n)=>({id:w,type:"system",text:n,speaker:""}),w("routeWangScript",[(e=(w,n,e,a)=>({id:w,type:"narration",text:n,speaker:"",background:e,effects:a}))("wb-s1-1","王博士线专属剧情\n\n你穿过警报灯闪烁的走廊——走廊尽头，王博士正站在白板前画代谢通路图。粉笔灰落在他的袖子上。他对警报视若无睹——仿佛早已习惯。","corridor"),a("wb-s1-2","林墨","linmo","王博士！发酵罐的通风系统需要重启——您有B3层总控的权限！","linmo"),,e("wb-s1-3",'他没有问"你怎么知道"。没有惊讶。没有质疑。只是慢慢转身——推了推老花镜——从镜片上方看了你整整三秒钟。像是在确认一件他等了很久的事。',"corridor"),a("wb-s1-4","王博士","wang","……你身上有他的影子。",void 0,{affection:{wang:10}}),a("wb-s1-5","王博士","wang","跟我来。","wang"),e("wb-s1-6","他带你走向电梯——不是普通的电梯。是需要指纹、虹膜、声纹三重验证的VIP电梯。王博士把手放在面板上。没有反应。他皱了皱眉——然后输入了一串手写密码。电梯开了。","corridor"),a("wb-s1-7","王博士","wang","张总改了我的生物识别权限。但他忘了——",void 0,{affection:{wang:5}}),a("wb-s1-8","王博士","wang","密码是存在这里的。",void 0),e("wb-s1-9","他指了指自己的脑袋。电梯开始下降。几十秒的时间——他用电梯墙上的触摸屏调出了一张代谢通路图。","corridor"),a("wb-s1-10","王博士","wang","年轻人。我考你一个问题。这是你父亲当年考我的。","wang"),e("wb-s1-11","屏幕上——糖酵解与糖异生的完整通路。三条红色虚线标出的步骤——不可逆。三条绿色箭头——绕道。王博士的手指悬停在第一个红叉上方。","corridor"),o("wb-s1-12","电梯下降的嗡鸣声中——王博士指着屏幕上的代谢通路图。",{question:"糖异生需要绕过糖酵解的哪三个不可逆步骤？分别由什么酶催化绕道？",options:[{label:"A",text:"①己糖激酶→绕过：葡萄糖-6-磷酸酶(仅肝/肾) ②PFK-1→绕过：果糖二磷酸酶-1 ③丙酮酸激酶→绕过：丙酮酸羧化酶(需生物素)+PEPCK(需GTP)",correct:!0},{label:"B",text:"只有PFK-1需要绕过——其他步骤可逆",correct:!1},{label:"C",text:"所有步骤都可逆——不需要绕道",correct:!1},{label:"D",text:"只有己糖激酶需要绕过——丙酮酸激酶本来就是可逆的",correct:!1}],explanation:"糖酵解三个不可逆步骤及糖异生绕道：①G→G-6-P(己糖激酶/葡萄糖激酶)→绕过：G-6-P→G(葡萄糖-6-磷酸酶，仅肝/肾皮质表达)；②F-6-P→F-1,6-2P(PFK-1)→绕过：F-1,6-2P→F-6-P(果糖二磷酸酶-1，被ATP和柠檬酸激活，被AMP和F-2,6-BP抑制)；③PEP→丙酮酸(丙酮酸激酶)→绕过：丙酮酸→草酰乙酸(丙酮酸羧化酶，需生物素为辅酶)→PEP(PEPCK，需GTP)。",knowledgeId:"gluconeogenesis_bypass",knowledgeTitle:"糖异生三个绕道路线——丙酮酸羧化酶/PEPCK/果糖二磷酸酶-1/葡萄糖-6-磷酸酶"},[a("wb-s1-12c","王博士","wang","满分。",void 0,{affection:{wang:15}}),a("wb-s1-13","王博士","wang","你父亲——林远山——当年在研究生面试时也答对了这道题。一字不差。",void 0,{affection:{wang:10}}),e("wb-s1-14","他转过身。透过老花镜——你看到他的眼眶有些模糊。不是老花的原因。","corridor"),a("wb-s1-15","王博士","wang","我认出你了。从你踏进这栋楼的第一秒。","wang",{affection:{wang:10}})],[a("wb-s1-12w","王博士","wang","三个不可逆步骤。己糖激酶。PFK-1。丙酮酸激酶。绕过它们的四个酶——是糖异生的关键。记住了。","wang")]),a("wb-s1-16","林墨","linmo","……您认识我父亲？","linmo"),a("wb-s1-17","王博士","wang","他是我的师兄。也是我——这一生——最好的朋友。",void 0,{affection:{wang:10}}),e("wb-s1-18","电梯停了。门打开——前方是B3层的暗红色应急灯光。大型低温休眠舱排列在走廊两侧。控制面板上闪烁着绿色的时间戳数据。","b3_cryo"),a("wb-s1-19","王博士","wang","我会告诉你一切。但不是现在。先救这栋楼。","wang"),e("wb-s2-1","王博士熟练地在密码面板上操作——他显然来过这里无数次了。主控屏幕上的数据流飞速滚动。","b3_cryo"),a("wb-s2-2","王博士","wang","重启通风系统需要三个步骤。我先处理。",void 0),e("wb-s2-3","但他的眉头越来越紧。监控屏幕上——发酵罐内蛋白的圆二色谱(CD Spectra)显示：208nm和222nm处的α-螺旋特征峰在急剧下降。217nm处的β-折叠峰在上升。200nm以下的无规卷曲信号在暴涨。最后四条曲线——全部归为一条平滑的噪声线。","b3_cryo"),a("wb-s2-4","王博士","wang","有人在补料管道里加了化学变性剂。QZ-1蛋白已经开始不可逆变性和聚集了。",void 0),a("wb-s2-5","王博士","wang",'你看——这种聚集体——本质上和朊病毒蛋白一样——会把正常的蛋白也"教坏"。不是意外泄漏。是有人故意投放的。',"wang"),o("wb-s2-6","王博士打开紧急排料阀门——同时回头看着你。",{question:"蛋白质的二级结构主要由什么化学键维持？变性后哪些结构层次被破坏？",options:[{label:"A",text:"主链骨架C=O与N-H之间的氢键维持二级结构；变性破坏空间构象(二/三/四级)但不破坏一级结构(肽键)",correct:!0},{label:"B",text:"肽键维持二级结构；变性破坏一级结构",correct:!1},{label:"C",text:"二硫键维持二级结构；变性只破坏四级结构",correct:!1},{label:"D",text:"离子键维持二级结构；变性破坏所有结构层次包括肽键",correct:!1}],explanation:"蛋白质二级结构(α-螺旋、β-折叠、β-转角、无规卷曲)由主链骨架的C=O与N-H之间形成的氢键维持。变性破坏的是非共价键(氢键、离子键、疏水作用力)和二硫键(可被β-巯基乙醇还原)，但不影响由肽键(共价键)连接的一级结构。这正是Anfinsen经典实验的核心发现——核糖核酸酶A在8M尿素+β-巯基乙醇中完全变性失活，透析去除变性剂后自发恢复100%活性。",knowledgeId:"protein_denaturation",knowledgeTitle:"蛋白质变性——空间构象破坏/一级结构保留/Anfinsen实验"},[a("wb-s2-6c","王博士","wang","很好。Anfinsen因为这个实验拿了1972年诺贝尔化学奖。核糖核酸酶A——124个氨基酸——8个半胱氨酸形成4对二硫键——在8M尿素和β-巯基乙醇中完全展开——透析后——自动折叠回活性构象。",void 0,{affection:{wang:10}}),a("wb-s2-7","王博士","wang","一级结构决定高级结构。这是生化领域最深刻的真理之一。就像——一个人骨子里的东西，决定了他在危机中会成为怎样的人。","wang",{affection:{wang:5}})],[a("wb-s2-6w","王博士","wang","氢键。主链上的。不是侧链。变性破坏的只是空间构象——肽键还在。一级结构不参与变性。记住了。","wang")]),e("wb-s2-8","通风系统重新启动。发酵罐排料完成。所有人的生命暂时安全。但王博士没有停下来——他站在监控屏前，盯着那些已经变成噪声的CD曲线，沉默了很久。","b3_cryo"),e("wb-s3-1","深夜。王博士的办公室。只有一盏台灯亮着。窗外是城市的万家灯火——但这里只有两个人和一本泛黄的笔记本。","office"),a("wb-s3-2","王博士","wang","坐。",void 0),e("wb-s3-3","他把一本泛黄的皮革封面笔记本推到桌面上。封面已经磨损——边缘卷起——有些页角被反复翻阅磨圆了。","office"),a("wb-s3-4","王博士","wang","这是我和你父亲——二十五年的实验记录。",void 0,{affection:{wang:15}}),e("wb-s3-5","他翻开第一页。上面是两个人并排的签名。钢笔字——蓝色墨水已经褪色——但笔迹依然清晰有力。","office"),a("wb-s3-6","王博士","wang","林远山·王建国。1999年3月。浙江大学生化楼307。",void 0),e("wb-s3-7",'他的手指按在"林远山"三个字上。停在那里。像是想从一个名字里——获得早已失落的温度。',"office"),a("wb-s3-8","王博士","wang","翻到最后一页。","wang"),e("wb-s3-9","你翻过去。最后一页是所有记录中字迹最潦草的——有些地方被水浸过。不是试剂。是眼泪。","office"),a("wb-s3-10","王博士","wang","1999年12月。我们在马里亚纳海沟热液喷口的古菌样本中——提取了一种新酶。特殊的铁硫簇。极端条件下的催化活性。","wang"),a("wb-s3-11","王博士","wang","你父亲给它取名叫QZ-酶。QuanTum-Zyme。",void 0),e("wb-s3-12","他的声音开始变低。不是疲惫——是在努力控制着某种东西。","office"),a("wb-s3-13","王博士","wang","然后我们发现了一个可怕的真相。这个酶能在特定DNA序列存在时——在濒死细胞中触发一种量子纠缠效应——将意识回溯到上一个睡眠节点。",void 0),a("wb-s3-14","王博士","wang",'简单来说——它能让人"重来"。',"wang"),a("wb-s3-15","林墨","linmo","……你们测试过了？在人身上？","linmo"),e("wb-s3-16","王博士摘下老花镜。他没有擦拭——任由泪水模糊镜片。沉默了整整十秒。","office"),a("wb-s3-17","王博士","wang","你母亲。",void 0,{affection:{wang:20}}),a("wb-s3-18","王博士","wang","她得了急性髓系白血病。晚期。无药可救。你父亲为了救她——私自给自己注射了QZ-酶。他是第一个适配体——那时候我们不知道这个称呼。我们只知道——他的DNA能让酶激活。","wang"),a("wb-s3-19","王博士","wang","他进入轮回。一次又一次——回到你母亲确诊之前——尝试每一种可能的治疗方案。",void 0,{affection:{wang:10}}),a("wb-s3-20","王博士","wang","连续——二十一次轮回。",void 0),e("wb-s3-21","他停住了。手指微微颤抖。办公桌上的台灯把他的影子投在墙上——一个苍老的、背负了太多东西的轮廓。","office"),a("wb-s3-22","王博士","wang","每一次轮回都会消耗端粒。二十一次之后——他的端粒缩短到了临界值以下。身体开始全面衰老。头发白了。皮肤皱了。但他没有放弃。","wang"),a("wb-s3-23","王博士","wang","在第——二十二——次轮回中。他找到了。一个当时还在临床试验中的CAR-T治疗方案。",void 0,{affection:{wang:15}}),e("wb-s3-24","他的声音终于彻底哑了。","office"),a("wb-s3-25","王博士","wang","那个方案——救回了你母亲。她活了。完全康复了。",void 0),a("wb-s3-26","王博士","wang","但你父亲的端粒——已经完全耗尽。Hayflick极限被越过。全身细胞进入衰老危机。",void 0),a("wb-s3-27","王博士","wang",'半年后——"车祸身亡"。',void 0,{affection:{wang:25}}),e("wb-s3-28","他说这四个字的语气——像是在说一个他用了二十五年都没能消化的事实。","office"),a("wb-s3-29","林墨","linmo","……张启明知道那不是车祸。","linmo"),a("wb-s3-30","王博士","wang","张启明——当时还是我们的师弟。他在你父亲的实验数据中——看到了QZ-酶有军事和商业价值。你父亲拒绝交出数据。",void 0),a("wb-s3-31","王博士","wang",'张启明不知道的是——你父亲在最后一次轮回结束后——把所有的核心数据拆分、加密。他留了一把"钥匙"。',void 0),e("wb-s3-32","王博士抬起头。透过模糊的镜片——他看着你。不是在看你——是在看你脸上他找了二十五年的东西。","office"),a("wb-s3-33","王博士","wang","钥匙就是你的DNA。你父亲——把一切——都写在了你的基因里。","wang",{affection:{wang:30}}),e("wb-cg-notebook",'台灯昏黄。笔记本的最后一页——字迹潦草——被水浸过——不是试剂，是眼泪。王博士苍老的手指按在"林远山"三个字上——像是在从二十五年冰冷的时光中——汲取最后一点温度。',"office"),e("wb-s3-34",'台灯昏黄。笔记本上的签名在泪痕中显得模糊。王博士苍老的手指按在"林远山"三个字上——像是在从二十五年冰冷的时光中——汲取最后一点温度。',"office"),i("wb-s3-keyitem","获得关键道具：原始实验记录本\n\n内含QZ-酶全部原始数据 + 林远山研究遗稿\n王博士线核心信息已全部解锁"),e("wb-s4-1","第二天。王博士带你进入他的小型书房——堆满文献和研究笔记的储藏室。墙角有一张旧照片——两个年轻人穿着白大褂，在一台蛋白质测序仪前抱臂微笑。","office"),a("wb-s4-2","王博士","wang","你父亲在设计QZ-酶的时候——在最关键的活性位点外面——加了一段65个氨基酸的保护性环肽序列。",void 0,{affection:{wang:10}}),e("wb-s4-3","他翻开笔记本的某一页。上面是手绘的蛋白结构图——主链折叠成复杂的拓扑——但在活性中心上方——一个额外的环状结构——盖住了催化位点。","office"),a("wb-s4-4","王博士","wang","这个保护环——不是结构性的。是功能性的。当宿主体内环境处于危机状态——pH下降、氧化应激升高、或者特定信号分子出现时——这个环肽会发出一个静电信号。",void 0),a("wb-s4-5","王博士","wang","信号一旦发出——QZ-酶所有金属辅因子依赖的催化活性——全部停止。整个酶进入锁定状态。","wang"),e("wb-s4-6","他又翻到另一页。林远山的笔迹——比任何一页都要工整。旁边画了一个小小的婴儿襁褓。","office"),a("wb-s4-7","王博士","wang","一个父亲——在给未出生的孩子——写一段守护程序。",void 0,{affection:{wang:20}}),a("wb-s4-8","王博士","wang",'他在你出生前的最后一篇实验记录里写道——"如果有一天我的孩子需要进入QZ-酶的网络——这个环肽会保护ta。只有ta的DNA能解锁。"',void 0),o("wb-s4-9","王博士拿起一支笔——在白板上画下了酶原激活的示意图。",{question:"什么是酶原？酶原激活的经典例子是什么？其生理意义何在？",options:[{label:"A",text:"酶原(zymogen)是酶的无活性前体——需在特定条件下切除部分肽段才能转变为活性酶；经典例子：胰蛋白酶原→胰蛋白酶(肠激酶切割)，胃蛋白酶原→胃蛋白酶(酸性pH自激活)",correct:!0},{label:"B",text:"酶原就是辅酶——与酶结合后产生活性",correct:!1},{label:"C",text:"酶原是失活的酶——通过加热可以恢复活性",correct:!1},{label:"D",text:"酶原只存在于植物细胞中——动物细胞没有",correct:!1}],explanation:"酶原(zymogen)是酶的无活性前体。必须在特定条件下切除部分肽段(通常为N端前肽)才能转变为活性酶。经典例子：①胰蛋白酶原→胰蛋白酶——由肠激酶在小肠中催化切割N端六肽Val-Asp-Asp-Asp-Asp-Lys；②胃蛋白酶原→胃蛋白酶——由胃酸(pH<5)自催化切割N端44个氨基酸；③凝血因子均为酶原——形成级联放大系统。酶原激活的生理意义：防止酶在合成部位(如胰脏)就发挥催化作用造成组织自溶。",knowledgeId:"zymogen_activation",knowledgeTitle:"酶原激活——胰蛋白酶原/胃蛋白酶原/凝血级联"},[a("wb-s4-9c","王博士","wang",'正是如此。你父亲的保护环肽——本质上就是一种"酶原锁"。它让QZ-酶在不对的宿主中保持无活性状态——只有在正确的DNA匹配时——就像是肠激酶切割胰蛋白酶原——锁才被打开。',void 0,{affection:{wang:15}}),a("wb-s4-10","王博士","wang","你父亲设计的不是一个工具。是一把只有你才能打开的锁。",void 0,{affection:{wang:10}})],[a("wb-s4-9w","王博士","wang","胰蛋白酶原。肠激酶。激活切割。凝血因子也是酶原。这是生化中最精巧的设计之一——在需要时才激活。你的父亲——给了你同样的保护。","wang")]),e("wb-s5-1","又过了一天。你去找王博士时——发现他脸色苍白，额头冒冷汗。他捂着腹部——但仍然坚持站在白板前看代谢通路图。","office"),a("wb-s5-2","林墨","linmo","王博士——您怎么了？","linmo"),a("wb-s5-3","王博士","wang","没什么。年纪大了。血氨有点偏高。",void 0),e("wb-s5-4","他从抽屉里拿出一瓶乳果糖浆。手有些抖——但还是平静地拧开盖子。","office"),a("wb-s5-5","王博士","wang","肝脏——尿素循环——处理不掉多余的氨。",void 0),o("wb-s5-6","王博士喝完乳果糖——缓了过来——但他接下来的话让你后背发凉。",{question:"尿素循环的关键限速酶是什么？尿素生成的原料包括哪些？",options:[{label:"A",text:"氨甲酰磷酸合成酶I(CPS-I)——存在于肝细胞线粒体内——以NH₃为氮源——受N-乙酰谷氨酸别构激活；原料：NH₃+CO₂+天冬氨酸+3ATP",correct:!0},{label:"B",text:"精氨酸酶；原料：尿酸+CO₂",correct:!1},{label:"C",text:"鸟氨酸转氨甲酰酶；原料：谷氨酰胺+CO₂",correct:!1},{label:"D",text:"CPS-II(细胞液)——以谷氨酰胺为氮源——与CPS-I是同一个酶",correct:!1}],explanation:"CPS-I(线粒体)以游离NH₃为氮源，受N-乙酰谷氨酸别构激活。CPS-II(细胞液)以谷氨酰胺为氮源，无别构激活剂，受UMP反馈抑制——两者是完全不同的酶。尿素循环总反应：NH₃+CO₂+天冬氨酸+3ATP→尿素+延胡索酸+2ADP+AMP+PPi。血氨浓度升高(高氨血症)→肝性脑病——NH₃穿过血脑屏障→干扰脑能量代谢和神经递质(Glu/GABA)合成。",knowledgeId:"urea_cycle_cps1",knowledgeTitle:"尿素循环——CPS-I限速酶/高氨血症/肝性脑病"},[a("wb-s5-6c","王博士","wang","你很清楚地记住了CPS-I和CPS-II的区别。这很重要。因为——",void 0,{affection:{wang:10}}),e("wb-s5-7","他放下乳果糖。看着自己的腹部。语气平静得像在陈述一个别人的诊断结果。","office"),a("wb-s5-8","王博士","wang","张总植入我体内的生物炸弹——就是利用了氨代谢的弱点。",void 0),a("wb-s5-9","王博士","wang","胶囊外层——pH敏感脂质体。内层——基因工程改造过的肉毒杆菌毒素变体。一旦张总用特定电磁频率激活——胶囊破裂——毒素进入线粒体。","wang"),a("wb-s5-10","王博士","wang","ATP合成停止。细胞凋亡启动。整个肝脏——首当其冲——尿素循环被切断——血氨飙升——肝昏迷——死亡。",void 0),a("wb-s5-11","王博士","wang","他在给我做了一个——生物版的——定时炸弹。","wang",{affection:{wang:15}})],[a("wb-s5-6w","王博士","wang","CPS-I——线粒体——以NH₃为氮源——受N-乙酰谷氨酸激活。CPS-II——细胞液——以谷氨酰胺为氮源。两个酶不要搞混。这关系到你能不能救我的命。","wang")]),a("wb-s5-12","林墨","linmo","……他在你身体里装了炸弹。多久了？","linmo"),a("wb-s5-13","王博士","wang","六年。从我发现他私下和DARPA谈判的那一天起。",void 0),e("wb-s5-14","他说这话的时候没有愤怒。没有恐惧。只有一种奇怪的——如释重负。好像等了很久终于可以说了。","office"),a("wb-s5-15","王博士","wang","所以请记住我接下来要教你的东西。不是为了考试。是为了——在我倒下之后——你还有机会完成你父亲留下的工作。",void 0,{affection:{wang:20}}),e("wb-s6-1","王博士从书架上抽出一本论文——封面已经泛黄——边缘贴着便签。他翻到其中一页——上面画着一条代谢通路：丝氨酸→THF→5-甲基-THF→B12→同型半胱氨酸→甲硫氨酸→SAM。","office"),a("wb-s6-2","王博士","wang",'你父亲临终前给我留了一句话——"告诉那孩子——钥匙在甲基里。"',void 0,{affection:{wang:10}}),a("wb-s6-3","王博士","wang",'我花了二十多年——才明白他说的"甲基"是什么意思。不是基因序列。是DNA甲基化。表观遗传。',"wang"),a("wb-s6-4","王博士","wang",'你父亲的遗稿中有一份加密序列——要解密它——需要了解你DNA中特定位置的甲基化模式。不是遗传的碱基序列——是"写入"的甲基化模式。因为甲基化模式是后天获得的——不是从父母遗传的——所以只有你自己的细胞中的甲基化模式才能解密。',void 0),o("wb-s6-5","王博士的手指沿着代谢通路图移动——从丝氨酸开始——一直走到SAM。",{question:"一碳单位在体内以什么形式转运？活性甲基的供体是什么？",options:[{label:"A",text:"一碳单位以四氢叶酸(THF)为载体转运；体内最重要的活性甲基供体是S-腺苷甲硫氨酸(SAM)",correct:!0},{label:"B",text:"一碳单位以NADPH为载体转运；活性甲基供体是叶酸",correct:!1},{label:"C",text:"一碳单位以维生素B12为载体转运；活性甲基供体是甜菜碱",correct:!1},{label:"D",text:"一碳单位以生物素为载体转运；活性甲基供体是ATP",correct:!1}],explanation:"一碳单位(甲基-CH₃、亚甲基=CH₂、次甲基≡CH、甲酰基-CHO、亚氨甲基-CH=NH)主要来源于丝氨酸、甘氨酸、组氨酸、色氨酸的分解代谢。四氢叶酸(THF)是一碳单位的载体(叶酸缺乏→一碳单位代谢障碍→巨幼细胞性贫血)。SAM(S-腺苷甲硫氨酸)由甲硫氨酸+ATP经SAM合成酶催化生成——是体内最重要的活性甲基供体，参与DNA/RNA/蛋白质甲基化、神经递质合成等。DNMT(DNA甲基转移酶)使用SAM将甲基转移到CpG二核苷酸的胞嘧啶第5位碳上。",knowledgeId:"one_carbon_sam",knowledgeTitle:"一碳单位代谢——THF载体/SAM活性甲基供体/DNA甲基化"},[a("wb-s6-5c","王博士","wang","完全正确。MT-ND5基因启动子第-127位的CpG——这个特定位置的甲基——就是你父亲说的钥匙。",void 0,{affection:{wang:15}}),a("wb-s6-6","王博士","wang","DNMT使用SAM把甲基加上。TET蛋白把甲基氧化去除。这是表观遗传的动态平衡。你父亲的加密方案——就是利用了你出生前他在你DNA中植入的特定甲基化模式。",void 0),a("wb-s6-7","王博士","wang","只有你的细胞——只有你的SAM——只有你的甲基化模式——能解开他留下的加密数据。张总研究了二十五年——什么都破解不了。不是因为他不够聪明。是因为他不是你。","wang",{affection:{wang:10}})],[a("wb-s6-5w","王博士","wang","四氢叶酸——THF——一碳单位的载体。SAM——S-腺苷甲硫氨酸——活性甲基的供体。DNMT使用SAM把甲基转移到DNA上。这条通路——你父亲用它来给你留了一把钥匙。","wang")]),e("wb-s7-1","王博士的身体越来越差。但每天早晨——他仍然准时出现在办公室里——白板上多出了新的代谢通路图。今天——Michaelis-Menten方程。","office"),a("wb-s7-2","王博士","wang","CPS-I的Km值对你的解毒剂设计至关重要。Km越小——亲和力越高——你就越能用更低的剂量竞争性抑制张总的毒素。",void 0),o("wb-s7-3","王博士在白板上画下了双倒数曲线图(Lineweaver-Burk Plot)——三条直线相交于不同的点。",{question:"在酶的三种可逆抑制中——竞争性抑制如何影响Km和Vmax？非竞争性抑制又如何？",options:[{label:"A",text:"竞争性抑制：Km↑(表观亲和力↓)，Vmax不变(增加[S]可克服)；非竞争性抑制：Vmax↓，Km不变",correct:!0},{label:"B",text:"两者都降低Vmax——区别在于Km变化方向",correct:!1},{label:"C",text:"竞争性抑制不可逆——底物浓度增加无效",correct:!1},{label:"D",text:"非竞争性抑制增加Vmax——减少Km",correct:!1}],explanation:'竞争性抑制：抑制剂(I)与底物(S)结构相似——竞争结合酶的同一活性位点。动力学：Km↑(表观亲和力降低，需要更多底物才能达到½Vmax)，Vmax不变(增加足够[S]可完全克服抑制)。Lineweaver-Burk图：1/V轴截距不变(Vmax不变)，1/[S]轴截距改变(Km↑)。非竞争性抑制：I与E-S复合体结合(不与活性位点竞争)。Vmax↓(部分酶"被卡住"无法转化底物)，Km不变(剩余活性酶的底物亲和力未改变)。Lineweaver-Burk图：1/V轴截距改变，1/[S]轴截距不变。',knowledgeId:"enzyme_inhibition",knowledgeTitle:"酶的三种可逆抑制——竞争性/非竞争性/反竞争性(Km与Vmax变化)"},[a("wb-s7-3c","王博士","wang","很好。你设计的解毒剂——应该是一个竞争性抑制剂。结构与毒素类似——与毒素竞争线粒体膜上的转运蛋白——足够高的浓度就可以让毒素无法进入线粒体。",void 0,{affection:{wang:10}}),a("wb-s7-4","王博士","wang","这就是你父亲的风格——不是摧毁敌人——是堵住门口。他从来不喜欢破坏。只喜欢守护。","wang",{affection:{wang:5}})],[a("wb-s7-3w","王博士","wang","竞争性——Km升高——Vmax不变。非竞争性——Vmax降低——Km不变。这两个不要搞混。竞争性抑制剂和底物抢座位。非竞争性的直接把人从座位上拽下来。","wang")]),e("wb-s8-1",'几天后。王博士被张总叫去"谈话"。回来的时候——他捂着腹部——白大褂袖子上沾着暗红色的血迹。但他没有去医务室。他去了办公室——拿起了粉笔。',"office"),a("wb-s8-2","林墨","linmo","王博士——！您需要去医院——","linmo"),a("wb-s8-3","王博士","wang","医院救不了我。但你现在需要听我说。氨基酸代谢——三种脱氨基方式。",void 0,{affection:{wang:15}}),e("wb-s8-4","他用沾着血迹的手指在白板上画出谷氨酸→α-酮戊二酸+NH₃的反应。粉笔尖在抖。但字迹依然工整。","office"),o("wb-s8-5","王博士的白大褂上血迹在扩散——但他的声音依然平静。",{question:"体内氨基酸脱氨基最主要的方式是什么？谷氨酸脱氢酶有什么独特之处？",options:[{label:"A",text:"联合脱氨基作用(转氨+氧化脱氨联合)——谷氨酸脱氢酶是唯一能同时利用NAD⁺和NADP⁺的脱氨酶——存在于线粒体内",correct:!0},{label:"B",text:"单一氧化脱氨基——谷氨酸脱氢酶只能使用NAD⁺",correct:!1},{label:"C",text:"转氨基——谷氨酸脱氢酶在细胞液中",correct:!1},{label:"D",text:"直接脱羧——不需要脱氨",correct:!1}],explanation:"体内氨基酸脱氨基最主要的方式是联合脱氨基作用：①转氨基——氨基酸将氨基转移给α-酮戊二酸→生成谷氨酸+相应α-酮酸(转氨酶如ALT/AST催化，辅酶PLP)；②氧化脱氨基——谷氨酸脱氢酶催化谷氨酸→α-酮戊二酸+NH₃(NAD⁺/NADP⁺作为电子受体)。谷氨酸脱氢酶是唯一能同时利用NAD⁺和NADP⁺的脱氨酶——位于线粒体内——别构受ATP/GTP抑制、ADP/GDP激活。8种必需氨基酸：缬氨酸、异亮氨酸、亮氨酸、赖氨酸、甲硫氨酸、苯丙氨酸、苏氨酸、色氨酸。",knowledgeId:"amino_acid_deamination",knowledgeTitle:"氨基酸脱氨基——联合脱氨/谷氨酸脱氢酶/必需氨基酸"},[a("wb-s8-5c","王博士","wang","谷氨酸脱氢酶——线粒体——永远在最关键的位置。就像你父亲当年。",void 0,{affection:{wang:20}}),a("wb-s8-6","王博士","wang",'还有一件事——八种必需氨基酸。身体不能合成——必须从食物中摄取。缬、异亮、亮、赖、甲硫、苯丙、苏、色。记住它们。你父亲临终前——我给他在医院送了一碗粥——他笑说——"蛋白不够——必需氨基酸不全。"',void 0)],[a("wb-s8-5w","王博士","wang","联合脱氨——转氨加上氧化脱氨。谷氨酸脱氢酶——线粒体——NAD⁺和NADP⁺都能用。必需氨基酸八种——身体自己造不出来。这些都是你父亲教我的。","wang")]),e("wb-s9-1","那天晚上。警报响了——和第一天一样刺耳。但这一次——你赶到王博士办公室时——门虚掩着。灯亮着。人倒在地上。","office"),e("wb-s9-2","白大褂被血浸透——暗红色在白色布料上像是一朵正在绽放的花。粉笔还握在他手里——白板上写着最后一行方程式。字迹从工整慢慢歪斜——最后几个字母已经几乎无法辨认。","office"),a("wb-s9-3","林墨","linmo","王博士——！","linmo"),e("wb-s9-4",'他还有意识。看到你冲进来——他居然笑了一下。不是苦笑。是那种——"终于等到你了"的欣慰。',"office"),a("wb-s9-5","王博士","wang","……别慌。我还能给——再给你讲——五分钟。",void 0,{affection:{wang:25}}),a("wb-s9-6","王博士","wang","他引爆了——一部分。不是全部。pH敏感的脂质体——没全破——所以我还没死——只是——肝脏——撑不住了。","wang"),e("wb-s9-7","他从白大褂内侧口袋里——颤巍巍地——掏出一张旧照片。照片边缘已经泛黄——有两道折痕——显然被反复拿出来看过无数次。","office"),a("wb-s9-8","王博士","wang","你——和你爸一样倔。",void 0,{affection:{wang:30}}),e("wb-s9-9","他把照片塞进你手里。手指冰凉。","office"),a("wb-s9-10","王博士","wang","第一排——那个——就是你爸。左边——是我。右边——那个——","wang"),e("wb-s9-11","他停了很久。不是因为疼。是因为要说出的那个名字——他藏了二十五年。","office"),a("wb-s9-12","王博士","wang","右边那个——张启明。我们叫他——小师弟。他是我们实验室——第三个人。",void 0,{affection:{wang:35}}),a("wb-s9-13","王博士","wang","你知道你父亲——临终前——最后一句话——是什么吗。",void 0),e("wb-s9-14","泪水终于从他脸上滑落。沿着皱纹——滴在白大褂的血迹上。","office"),a("wb-s9-15","王博士","wang",'"我不恨他。但求求你们——停下来。"',void 0,{affection:{wang:40}}),a("wb-s9-16","王博士","wang","他从来没恨过任何人。他恨的是——这个东西被用来伤害别人。","wang"),e("wb-s10-1","你低下头——看着手里的照片。","office"),e("wb-s10-2","三十岁的林远山。年轻的王建国。年轻的张启明。三个人穿着白大褂——站在一台现在已经淘汰的蛋白质测序仪前——手里举着QZ-酶的第一支纯化管——笑得像孩子。阳光从实验室的窗户照进来——把三个年轻人的影子投在地板上——还没有分开。","office"),a("wb-s10-3","王博士","wang",'那是——1999年——圣诞节——前一天。我们第一次在电镜下看到QZ-酶的铁硫簇——像一颗——小太阳。你爸说——"我们找到了——能改变世界的东西。"',void 0,{affection:{wang:25}}),e("wb-s10-4","他的声音越来越轻。像是回到了那个下午——浙大生化楼307——窗外是冬天的梧桐树——实验室里的三个人还不知道——他们即将被一个发现改变一生。","office"),a("wb-s10-5","王博士","wang","二十五年了——那张照片——我一直放在白大褂口袋里。离心脏最近的地方。",void 0),e("wb-s10-6",'照片背面——钢笔字——蓝色墨水褪色成了浅灰——"远山·建国·启明——我们要一起走下去。"',"office"),a("wb-s10-7","王博士","wang","远山——我——没有走成——他想要的那条路。但——你来了。",void 0,{affection:{wang:50}}),a("wb-s10-8","王博士","wang","帮我——帮你父亲——把这个故事——画完。",void 0,{flag:"wang_final_trust"}),e("wb-s11-1","急救后——王博士被转移到了休息室。血压勉强维持——但肝功能的指标在持续恶化。他靠在枕头上——身边还放着一本翻开的生化教材。","office"),a("wb-s11-2","王博士","wang","我——还欠你——一堂课。化学渗透学说。质子动力势。这不是——在临终关怀——这是——实用知识。如果你要设计解毒剂——得让它穿过脂质体膜——你就需要——理解质子梯度。",void 0,{affection:{wang:10}}),o("wb-s11-3","王博士用颤抖的手在纸上画下了线粒体内膜的示意图。",{question:"化学渗透学说中——质子动力势(Δp)由哪两部分组成？质子浓度梯度储存在什么位置？",options:[{label:"A",text:"Δp = ΔΨ(跨膜电位差)+ ΔpH(跨膜pH梯度)；质子被泵到线粒体内膜外——储存在膜间隙",correct:!0},{label:"B",text:"Δp只由ΔpH组成——与膜电位无关",correct:!1},{label:"C",text:"质子被泵入线粒体基质——在内膜内部储存",correct:!1},{label:"D",text:"质子动力势储存在线粒体外膜",correct:!1}],explanation:"化学渗透偶联学说(Peter Mitchell, 1961, 1978年诺贝尔化学奖)核心：电子传递链将质子(H⁺)从线粒体基质泵到膜间隙→形成跨线粒体内膜的电化学质子梯度(质子动力势Δp)。Δp = ΔΨ(跨膜电位差，约0.14V，膜间隙较基质带更多正电荷) + ΔpH(跨膜pH梯度，约1.4单位，膜间隙pH更低)。ATP合酶(F₀F₁-ATPase)利用质子回流基质时释放的自由能驱动ATP合成(每3-4个H⁺合成1个ATP)。解偶联剂(UCP1/褐色脂肪产热、2,4-二硝基苯酚-DNP)消除质子梯度→氧化磷酸化解偶联→能量以热散失。",knowledgeId:"chemiosmotic_theory",knowledgeTitle:"化学渗透学说——质子动力势/Mitchell/氧化磷酸化偶联"},[a("wb-s11-3c","王博士","wang","如果——能用pH响应材料包裹解毒剂——只在内膜间隙的低pH环境下释放——就能保证——解毒剂只在靶细胞——才被激活。你父亲——当年也是——用同样的原理——设计了——保护环肽。",void 0,{affection:{wang:10}})],[a("wb-s11-3w","王博士","wang","质子动力势——两部分——ΔΨ和ΔpH。膜间隙——低pH——质子储存库。ATP合酶——利用回流——制造ATP。理解了这个——你就能设计——定向递送的解毒剂。","wang")]),e("wb-s12-1","深夜。监护仪的声音——滴——滴——滴——在安静的休息室里回响。王博士的生命体征在缓慢但不可逆转地下降。但他还睁着眼睛——看着天花板——嘴角带着一丝微笑。","dark"),a("wb-s12-2","王博士","wang","小林——给你——讲一个——故事。",void 0),a("wb-s12-3","王博士","wang",'1999年——你爸带我去——浙大旁边的——一家小面馆。一碗面——四块钱。他说——"建国——如果我们真的——找到了——可以改变生命的东西——我们得保证——它只被用来——救人。"',void 0,{affection:{wang:15}}),a("wb-s12-4","王博士","wang","我答应他了。但——没做到。二十五年——我一直——在害怕。怕张启明——怕死——怕面对——你。",void 0),e("wb-s12-5","他转过来——看着你——眼睛里有泪光——但更多的——是释然。","dark"),a("wb-s12-6","王博士","wang","你不像你爸——你比他——更像你自己。但——倔这一点——一模一样。",void 0,{affection:{wang:25}}),a("wb-s12-7","王博士","wang","你爸——把一切——写在了你基因里。我没能做到的——他相信——你能。我也——相信。",void 0,{affection:{wang:20}}),e("wb-s12-8","监护仪的蜂鸣声突然加速——然后又慢下来。","dark"),a("wb-s12-9","王博士","wang","我的——白大褂——右边口袋里——有一张——折叠的——纸。解毒剂的——配方。还有——你父亲——加密数据的——解密密钥。拿去吧。",void 0,{flag:"wang_antidote_received",affection:{wang:30}}),a("wb-s12-10","王博士","wang","远山——建国——启明——三个人——的故事——还没——写完。你——是——最后一页。",void 0),e("wb-s12-11","他的眼睛慢慢闭上。但嘴角的微笑还在。监护仪的声音——滴——滴——滴——","dark"),e("wb-s12-12","你低下头。手里握着那张发黄的旧照片。三个人。年轻的白大褂。阳光。梧桐树。还没有分开。","dark"),i("wb-end","▎王博士线 结局"),e("wb-end-he",'公司被查封。王博士虽然体内器官受损——但在你设计的解毒剂的帮助下——奇迹般地活了下来。几个月后。你在国际学术会议上发表了基于QZ-酶衍生的新型抗癌靶向药成果。台下——轮椅上——王博士老泪纵横。"这是林远山的心愿。等了二十五年。"你以父亲的名字——命名了新发现的治疗靶点。"远山蛋白"——被写入教科书。王博士回到了浙大生化楼307。他站在白板前——给大一新生讲糖异生——讲着讲着——在黑板上写下了三个年轻人的故事。"生物化学——不仅研究分子的结构和功能——它还研究——生命为什么值得被延续。"',"office",{condition:{affection:{wang:{min:80}}}}),e("wb-end-ne",'王博士的器官损伤不可逆。他活了下来——但余生需要轮椅和透析。他没能亲自看到你完成父亲的遗作。但他把一切都给了你——笔记本、配方、那张照片。你独自走完了剩下的路。在论文致谢中——你写道："感谢我的导师王建国博士——他教会我：酶是一把钥匙，只有对的底物才能激活。人也一样。"寄出论文的那一天——你在邮件里附上了那张三个人合影的扫描件。回复隔天就到了："看到了。远山会为你骄傲。我也会。"',"office",{condition:{affection:{wang:{min:50,max:79}}}}),e("wb-end-be",'你没有及时获得解毒剂的配方。张总引爆了生物炸弹。王博士在肝昏迷中——痛苦地——死去了。临终时——他依然认出了你——但喊的却是另一个名字："远山……你来接我了？"他以为是他的师兄来了。办公桌上——那本泛黄的实验记录本——依然翻到第一页。"林远山·王建国——1999年3月——浙大生化楼307。"两个签名。一个已经等了一个人二十五年。现在——只剩一个了。',"dark",{condition:{affection:{wang:{max:49}}}})])}}});